#include <stdio.h>
#include <inttypes.h>
int main(){
    int64_t N,M; if(scanf("%lld %lld",&N,&M)!=2) return 0;
    int64_t sumA=0; for(int i=0;i<N;i++){ int64_t x; scanf("%lld",&x); sumA+=x; }
    // read and discard initial edges
    for(int64_t i=0;i<M;i++){ int u,v; scanf("%d %d",&u,&v); }
    int64_t Q; scanf("%lld",&Q);
    int64_t curM=M;
    for(int64_t i=0;i<Q;i++){
        char type; scanf(" %c",&type);
        if(type=='+'){
            int u,v; scanf("%d %d",&u,&v); curM++; }
        else if(type=='-'){
            int u,v; scanf("%d %d",&u,&v); curM--; }
        else if(type=='?'){
            int64_t ans = sumA + 2*curM - N*(N-1)/2;
            printf("%lld\n", ans);
        }
    }
    return 0;
}

