import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int N = fs.nextInt();
        long M = fs.nextLong();
        long sumA = 0;
        for (int i = 0; i < N; i++) sumA += fs.nextLong();
        for (long i = 0; i < M; i++) { fs.nextInt(); fs.nextInt(); }
        int Q = fs.nextInt();
        long curM = M;
        StringBuilder sb = new StringBuilder();
        while (Q-- > 0) {
            char op = fs.next().charAt(0);
            if (op == '+') { fs.nextInt(); fs.nextInt(); curM++; }
            else if (op == '-') { fs.nextInt(); fs.nextInt(); curM--; }
            else { // '?'
                long ans = sumA + 2 * curM - (long)N * (N - 1) / 2;
                sb.append(ans).append('\n');
            }
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for speed
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') { sb.append((char)c); c = readByte(); }
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        long nextLong() throws IOException { return Long.parseLong(next()); }
    }
}

